use std::collections::HashMap;

fn main() {
    let mut map = HashMap::new();
    map.insert("key", "value");
    if let Some(value) = map.get("nonexistent_key") {
        println!("{}", value);
    } else {
        eprintln!("Key not found");
    }
}

